const query = $('接收政績列表查詢').first().json.query || {};
const page = Math.max(parseInt(query.page || '1', 10), 1);
const limit = Math.max(parseInt(query.limit || '100', 10), 1);
const tagFilter = String(query.tag || '').trim();
const featuredOnly = String(query.featured || '').toLowerCase() === 'true';
const rawItems = $input.all();

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'title') return (prop.title || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'date') return prop.date?.start || '';
  if (prop.type === 'url') return prop.url || '';
  if (prop.type === 'number') return prop.number ?? '';
  if (prop.type === 'checkbox') return prop.checkbox || false;
  return '';
}

function getFiles(prop) {
  if (!prop || prop.type !== 'files') return [];
  return (prop.files || []).map(f => f.file?.url || f.external?.url || '').filter(Boolean);
}

function getTags(prop) {
  return (prop?.multi_select || []).map(t => t.name).filter(Boolean);
}

function splitProcess(value) {
  return String(value || '').split(/\r?\n|、|,/).map(v => v.trim()).filter(Boolean).slice(0, 6);
}

function sourceFromProps(props) {
  const type = getText(props['政績類型']);
  if (type) return type;
  if (getText(props['相關案件編號'])) return '陳情案件';
  if (getText(props['相關會勘ID'])) return '現場會勘';
  if (getText(props['相關質詢ID'])) return '質詢成果';
  if (getText(props['相關提案ID'])) return '提案成果';
  return '政績資料庫';
}

let items = rawItems.map((item, index) => {
  const props = item.json.properties || {};
  const title = getText(props['政績標題']);
  const type = getText(props['政績類型']);
  const category = getText(props['議題類型']);
  const summary = getText(props['摘要']);
  const content = getText(props['詳細內容']) || summary;
  const coverImages = getFiles(props['封面圖片']);
  const beforeImages = getFiles(props['成果前圖片']);
  const afterImages = getFiles(props['成果後圖片']);
  const images = [...coverImages, ...beforeImages, ...afterImages];

  return {
    id: item.json.id || `achievement-${index + 1}`,
    title,
    type,
    source: sourceFromProps(props),
    category,
    tags: getTags(props['標籤']),
    date: getText(props['發布日期']),
    summary,
    content,
    featured: Boolean(getText(props['是否精選'])),
    image: coverImages[0] || images[0] || '',
    images,
    beforeImages,
    afterImages,
    process: splitProcess(content),
    videoUrl: getText(props['來源連結']),
    sortOrder: Number(getText(props['顯示排序']) || 999),
    status: getText(props['資料狀態'])
  };
}).filter(item => item.title && item.status !== '草稿' && item.status !== '隱藏');

if (tagFilter) items = items.filter(item => item.tags.includes(tagFilter) || item.category === tagFilter || item.type === tagFilter);
if (featuredOnly) items = items.filter(item => item.featured);

items.sort((a, b) => (a.sortOrder - b.sortOrder) || String(b.date).localeCompare(String(a.date)));

const total = items.length;
const totalPages = Math.max(1, Math.ceil(total / limit));
const safePage = Math.min(page, totalPages);
const start = (safePage - 1) * limit;
const pageItems = items.slice(start, start + limit);

return [{ json: { success: true, total, page: safePage, limit, totalPages, items: pageItems } }];
